const headerUser = {
  name: "murgo",
  email: "m@example.com",
  avatar: "https://api.dicebear.com/9.x/avataaars/svg?seed=murgo",
};

export function SettingsHeader() {
  const pathname = usePathname();

  // Trouver le titre de la section actuelle
