"use client";

import { Tick01Icon, Sorting05Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import * as React from "react";
import PhoneInput, { 
  type Value, 
  type Country, 
  type FlagProps, 
  getCountryCallingCode,
  isValidPhoneNumber
} from "react-phone-number-input";
import flags from "react-phone-number-input/flags";

import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Input } from "@/components/ui/input";

import "react-phone-number-input/style.css";

export type PhoneValue = Value;

interface PhoneInputFieldProps {
  value?: PhoneValue;
  onChange: (value: PhoneValue) => void;
  placeholder?: string;
  className?: string;
  disabled?: boolean;
}

export function PhoneInputField({
  value,
  onChange,
  placeholder,
  className,
  disabled,
}: PhoneInputFieldProps) {
  const isValid = value ? isValidPhoneNumber(value) : true;

  return (
    <div className={cn("flex flex-col gap-1.5", className)}>
      <PhoneInput
        disabled={disabled}
        value={value}
        onChange={(v) => onChange(v as PhoneValue)}
        defaultCountry="BJ"
        placeholder={placeholder ?? "Numéro de téléphone"}
        inputComponent={InputComponent}
        countrySelectComponent={CountrySelect}
        className={cn("flex", !isValid && value && "has-error")}
        limitMaxLength={true}
      />
      {!isValid && value && (
        <p className="text-[11px] text-destructive font-medium ml-1">
          Format de numéro invalide pour ce pays.
        </p>
      )}
    </div>
  );
}

const InputComponent = React.forwardRef<
  HTMLInputElement,
  React.ComponentProps<"input">
>(({ className, ...props }, ref) => (
  <Input
    className={cn("rounded-s-none rounded-e-lg border-s-0", className)}
    {...props}
    ref={ref}
  />
));
InputComponent.displayName = "InputComponent";

type CountrySelectOption = { label: string; value: Country };

type CountrySelectProps = {
  disabled?: boolean;
  value: Country;
  onChange: (value: Country) => void;
  options: CountrySelectOption[];
};

const CountrySelect = ({
  disabled,
  value,
  onChange,
  options,
}: CountrySelectProps) => {
  const handleSelect = React.useCallback(
    (country: Country) => {
      onChange(country);
    },
    [onChange],
  );

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          type="button"
          variant="outline"
          className={cn(
            "flex h-8 gap-1 rounded-e-none rounded-s-lg border-e-0 px-3 transition-colors outline-none focus-visible:z-10",
            disabled ? "opacity-50" : "",
          )}
          disabled={disabled}
        >
          <FlagComponent country={value} countryName={value} />
          <HugeiconsIcon
            icon={Sorting05Icon}
            className={cn(
              "-mr-2 h-4 w-4 opacity-50",
              disabled ? "hidden" : "opacity-100",
            )}
            size={16}
            strokeWidth={1.5}
          />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[300px] p-0" align="start">
        <Command>
          <CommandInput placeholder="Rechercher un pays..." />
          <CommandList>
            <ScrollArea className="h-72">
              <CommandEmpty>Aucun pays trouvé.</CommandEmpty>
              <CommandGroup>
                {options
                  .filter((x) => x.value)
                  .map((option) => (
                    <CommandItem
                      className="gap-2"
                      key={option.value}
                      onSelect={() => handleSelect(option.value)}
                    >
                      <FlagComponent
                        country={option.value}
                        countryName={option.label}
                      />
                      <span className="flex-1 text-sm">{option.label}</span>
                      {option.value && (
                        <span className="text-muted-foreground text-sm">
                          +{getCountryCallingCode(option.value)}
                        </span>
                      )}
                      <HugeiconsIcon
                        icon={Tick01Icon}
                        className={cn(
                          "ml-auto h-4 w-4",
                          option.value === value ? "opacity-100" : "opacity-0",
                        )}
                        size={16}
                        strokeWidth={1.5}
                      />
                    </CommandItem>
                  ))}
              </CommandGroup>
            </ScrollArea>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
};

const FlagComponent = ({ country, countryName }: FlagProps) => {
  const Flag = flags[country];

  return (
    <span className="flex h-5 w-7.5 shrink-0 overflow-hidden rounded-sm">
      {Flag && <Flag title={countryName} />}
    </span>
  );
};
FlagComponent.displayName = "FlagComponent";

"use client";

import * as React from "react";
import { HugeiconsIcon } from "@hugeicons/react";
import { Camera01Icon } from "@hugeicons/core-free-icons";
import { toast } from "sonner";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface ProfileImageUploadProps {
  value?: string;                      // URL ou base64 de l'image actuelle
  onChange: (value: string) => void;   // Appelé avec la nouvelle image en base64
  onReset?: () => void;                // Appelé pour réinitialiser/supprimer la photo
  fallbackText?: string;               // Initiales affichées si pas de photo
  size?: "sm" | "md" | "lg";           // Taille de l'avatar (défaut: "md")
  disabled?: boolean;                  // Désactiver toute interaction
  className?: string;
}

const ALLOWED_TYPES = ["image/jpeg", "image/png", "image/gif", "image/webp"];
const MAX_SIZE_MB = 1;

const sizeMap = {
  sm: "size-16",
  md: "size-24",
  lg: "size-32",
};

export function ProfileImageUpload({
  value,
  onChange,
  onReset,
  fallbackText = "MD",
  size = "md",
  disabled = false,
  className,
}: ProfileImageUploadProps) {
  const fileInputRef = React.useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = React.useState(false);

  const handleAvatarClick = () => {
    if (disabled) return;
    fileInputRef.current?.click();
  };

  const processFile = (file: File) => {
    if (!ALLOWED_TYPES.includes(file.type)) {
      toast.error("Format non supporté. Utilisez JPG, PNG, GIF ou WebP.");
      return;
    }

    if (file.size > MAX_SIZE_MB * 1024 * 1024) {
      toast.error("Image trop volumineuse (max 1 Mo).");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      onChange(base64String);
    };
    reader.readAsDataURL(file);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (disabled) return;
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (disabled) return;

    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  return (
    <div className={cn("flex flex-col sm:flex-row items-center gap-6", className)}>
      {/* Zone drag & drop + avatar cliquable */}
      <div
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={handleAvatarClick}
        className={cn(
          "relative group cursor-pointer rounded-full transition-all duration-200",
          isDragging && "border-4 border-primary scale-105",
          disabled && "cursor-not-allowed opacity-80"
        )}
      >
        <Avatar className={cn(sizeMap[size], "border-2 border-background shadow-sm")}>
          <AvatarImage src={value} className="object-cover" />
          <AvatarFallback className="bg-primary/10 text-primary font-medium">
            {fallbackText.split(" ").map(n => n[0]).join("").toUpperCase().slice(0, 2)}
          </AvatarFallback>
        </Avatar>

        {/* Overlay caméra */}
        {!disabled && (
          <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
            <HugeiconsIcon icon={Camera01Icon} className="text-white" size={24} strokeWidth={1.5} />
          </div>
        )}
      </div>

      {/* Input caché */}
      <input
        ref={fileInputRef}
        type="file"
        accept="image/jpeg,image/png,image/gif,image/webp"
        className="hidden"
        onChange={handleFileChange}
        disabled={disabled}
      />

      {/* Contrôles textuels */}
      <div className="flex flex-col gap-2">
        <div className="flex gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            onClick={handleAvatarClick}
            disabled={disabled}
          >
            Modifier la photo
          </Button>
          {value && onReset && (
            <Button
              type="button"
              variant="ghost"
              size="sm"
              className="text-destructive hover:text-destructive hover:bg-destructive/10"
              onClick={onReset}
              disabled={disabled}
            >
              Supprimer
            </Button>
          )}
        </div>
        <p className="text-xs text-muted-foreground italic">
          JPG, GIF ou PNG. Max size 1 Mo.
        </p>
      </div>
    </div>
  );
}

"use client"

import * as React from "react"
import { Select as SelectPrimitive } from "radix-ui"
import { ArrowDown01Icon, ArrowUp01Icon, Tick01Icon } from "@hugeicons/core-free-icons"
